import numpy as np


def nearest_neighbor(query, dataset, metric):
    """Find the index of the point in dataset closest to query under a metric."""
    q = np.asarray(query, dtype=float)
    points = [np.asarray(p, dtype=float) for p in dataset]

    def distance(x):
        diff = q - x
        if metric == "l1":
            return float(np.abs(diff).sum())
        if metric == "l2":
            return float(np.sqrt((diff ** 2).sum()))
        if metric == "linf":
            return float(np.abs(diff).max())
        if metric == "cosine":
            nq = float(np.sqrt((q ** 2).sum()))
            nx = float(np.sqrt((x ** 2).sum()))
            if nq == 0.0 or nx == 0.0:
                sim = 0.0
            else:
                sim = float((q * x).sum()) / (nq * nx)
            return 1.0 - sim
        raise ValueError(f"unknown metric: {metric!r}")

    dists = [distance(x) for x in points]
    return int(np.argmin(dists))
